1	export type Item = {
2	  type: string;
3	  material?: string;
4	  enchantment?: number;
5	  cursed?: boolean;
6	};
7	
8	export type Step = {
9	  op: string;
10	  items?: Item[];
11	};
12	
13	export type Scenario = {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	};
17	
18	export type ScenarioResult = {
19	  results: unknown[];
20	};
21	
22	const PROCESSING_FEE = 5;
23	const FIRST_INSURANCE_SURCHARGE = 0.1;
24	
25	const ITEM_BASE_PREMIUM: Record<string, number> = {
26	  sword: 100,
27	  rune: 25,
28	};
29	
30	const calculatePremium = (items: Item[]): number => {
31	  if (items.length === 0) return PROCESSING_FEE;
32	  const base = items.reduce((sum, item) => sum + ITEM_BASE_PREMIUM[item.type], 0);
33	  const withFirstInsurance = base + base * FIRST_INSURANCE_SURCHARGE;
34	  return Math.ceil(withFirstInsurance + PROCESSING_FEE);
35	};
36	
37	export const runScenario = (scenario: Scenario): ScenarioResult => {
38	  const results = scenario.steps.map((step) => ({
39	    premium: calculatePremium(step.items ?? []),
40	  }));
41	  return { results };
42	};
